--- /dev/null	2007-09-25 14:31:20.000000000 +0300
+++ files/extrapatch-bstack	2007-09-25 14:22:55.000000000 +0300
@@ -0,0 +1,55 @@
+--- /usr/local/src/dwm/dwm-4.4-virgin/dwm.c	2007-08-23 19:12:01.000000000 -0400
++++ dwm.c	2007-08-24 21:05:05.000000000 -0400
+@@ -174,6 +174,7 @@
+ void tile(void);
+ void togglebar(const char *arg);
+ void togglefloating(const char *arg);
++void bstack(void);			/* arranges all windows bottom stacked */
+ void togglemax(const char *arg);
+ void toggletag(const char *arg);
+ void toggleview(const char *arg);
+@@ -1605,6 +1605,44 @@ tile(void) {
+ }
+ 
+ void
++bstack(void) {
++	unsigned int i, n, nx, ny, nw, nh, mh, tw, th;
++	Client *c;
++
++	for(n = 0, c = nexttiled(clients); c; c = nexttiled(c->next))
++		n++;
++
++	/* window geoms */
++	mh = (n > 1) ? (wah * mwfact) / 1 : wah / (n > 0 ? n : 1);
++	th = (n > 1) ? (wah * (1 - mwfact)) / 1 : 0;
++	tw = (n > 1) ? waw / (n - 1) : 0;
++
++	for(i = 0, c = nexttiled(clients); c; c = nexttiled(c->next)) {
++		c->ismax = False;
++		nx = wax;
++		ny = way;
++		if(i < 1) {
++			ny += i * mh;
++			nw = waw - 2 * c->border;
++			nh = mh - 2 * c->border;
++		}
++		else {
++			nx += (i - 1) * tw;
++			ny += mh * 1;
++			if(i + 1 == n) { /* remainder */
++				nw = (wax + waw) - nx - 2 * c->border;
++			}
++			else {
++				nw = tw - 2 * c->border;
++			}
++			nh = th - 2 * c->border + 1;
++		}
++		resize(c, nx, ny, nw, nh, RESIZEHINTS);
++		i++;
++	}
++}
++
++void
+ togglebar(const char *arg) {
+ 	if(bpos == BarOff)
+ 		bpos = (BARPOS == BarOff) ? BarTop : BARPOS;
--- /dev/null	2007-09-25 14:31:20.000000000 +0300
