+--- dwm.c	1970-01-01 01:00:00.000000000 +0100
++++ dwm.c	2007-08-26 15:08:33.000000000 +0200
+@@ -188,6 +188,8 @@
+ void updatetitle(Client *c);
+ void view(const char *arg);
+ int xerror(Display *dpy, XErrorEvent *ee);
++void dwindle(void);			/* arranges all windows in a fibonacci diagonal */
++void spiral(void);			/* arranges all windows in a fibonacci spiral */	
+ int xerrordummy(Display *dsply, XErrorEvent *ee);
+ int xerrorstart(Display *dsply, XErrorEvent *ee);
+ void zoom(const char *arg);
+@@ -1647,6 +1647,71 @@
+ 	return textnw(text, strlen(text)) + dc.font.height;
+ }
+
++/* static */
++
++static void
++fibonacci(int shape) {
++	unsigned int i, n, nx, ny, nw, nh;
++	Client *c;
++
++	nx = wax;
++	ny = 0;
++	nw = waw;
++	nh = wah;
++	for(n = 0, c = nexttiled(clients); c; c = nexttiled(c->next))
++		n++;
++	for(i = 0, c = nexttiled(clients); c; c = nexttiled(c->next), i++) {
++		c->ismax = False;
++		if((i % 2 && nh / 2 > 2 * c->border)
++		|| (!(i % 2) && nw / 2 > 2 * c->border))
++		{
++			if(i < n - 1) {
++				if(i % 2)
++					nh /= 2;
++				else
++					nw /= 2;
++				if((i % 4) == 2 && !shape)
++					nx += nw;
++				else if((i % 4) == 3 && !shape)
++					ny += nh;
++			}
++			if((i % 4) == 0) {
++				if(shape)
++					ny += nh;
++				else
++					ny -= nh;
++			}
++			else if((i % 4) == 1)
++				nx += nw;
++			else if((i % 4) == 2)
++				ny += nh;
++			else if((i % 4) == 3) {
++				if(shape)
++					nx += nw;
++				else
++					nx -= nw;
++			}
++			if(i == 0)
++				ny = way;
++		}
++		resize(c, nx, ny, nw - 2 * c->border, nh - 2 * c->border, RESIZEHINTS);
++	}
++	focus(NULL);
++	restack();
++}
++
++/* extern */
++
++void
++dwindle(void) {
++	fibonacci(1);
++}
++
++void
++spiral(void) {
++	fibonacci(0);
++}
++
+ void
+ tile(void) {
+ 	unsigned int i, n, nx, ny, nw, nh, mw, mh, th;
--- /dev/null	2007-09-25 14:31:20.000000000 +0300
