@@ -0,0 +1,46 @@
+--- /dev/null	Thu Jan 01 00:00:00 1970 +0000
++++ dwm.c	Sat Sep 01 20:06:19 2007 +0200
+@@ -142,6 +142,7 @@
+ long getstate(Window w);
+ Bool gettextprop(Window w, Atom atom, char *text, unsigned int size);
+ void grabbuttons(Client *c, Bool focused);
++void grid(void);			/* arranges all windows on a grid */
+ unsigned int idxoftag(const char *tag);
+ void initfont(const char *fontstr);
+ Bool isarrange(void (*func)());
+@@ -775,6 +775,35 @@ getstate(Window w) {
+ 	return result;
+ }
+ 
++void
++grid(void) {
++	unsigned int i, n, cx, cy, cw, ch, aw, ah, cols, rows;
++	Client *c;
++
++	for(n = 0, c = nexttiled(clients); c; c = nexttiled(c->next))
++		n++;
++
++	/* grid dimensions */
++	for(rows = 0; rows <= n/2; rows++)
++		if(rows*rows >= n)
++			break;
++	cols = (rows && (rows - 1) * rows >= n) ? rows - 1 : rows;
++
++	/* window geoms (cell height/width) */
++	ch = wah / (rows ? rows : 1);
++	cw = waw / (cols ? cols : 1);
++
++	for(i = 0, c = nexttiled(clients); c; c = nexttiled(c->next), i++) {
++		c->ismax = False;
++		cx = (i / rows) * cw;
++		cy = (i % rows) * ch + (bpos == BarTop ? bh : 0); /* bh? adjust */
++		/* adjust height/width of last row/column's windows */ 
++		ah = ((i + 1) % rows == 0) ? wah - ch * rows : 0;
++		aw = (i >= rows * (cols - 1)) ? waw - cw * cols : 0;
++		resize(c, cx, cy, cw - 2 * c->border + aw, ch - 2 * c->border + ah, RESIZEHINTS);
++	}
++}
++
+ Bool
+ gettextprop(Window w, Atom atom, char *text, unsigned int size) {
+ 	char **list = NULL;
