@@ -0,0 +1,90 @@
+diff -r 795c26a59016 tile.c
+--- dwm.c	Sun Aug 26 12:54:20 2007 +0200
++++ dwm.c	Sun Aug 26 15:06:20 2007 +0200
+@@ -166,6 +166,7 @@
+ void scan(void);
+ void setclientstate(Client *c, long state);
+ void setlayout(const char *arg);
++void incnmaster(const char *arg);
+ void setmwfact(const char *arg);
+ void setup(void);
+ void spawn(const char *arg);
+@@ -1380,6 +1380,28 @@
+ 		drawbar();
+ }
+ 
++static unsigned int nmaster = NMASTER;
++
++void
++incnmaster(const char *arg) {
++	int i;
++
++	if(!isarrange(tile))
++		return;
++	if(!arg)
++		nmaster = NMASTER;
++	else {
++		i = atoi(arg);
++		if((nmaster + i) < 1 || wah / (nmaster + i) <= 2 * BORDERPX)
++			return;
++		nmaster += i;
++	}
++	if(sel)
++		arrange();
++	else
++		drawbar();
++}
++
+ void
+ setmwfact(const char *arg) {
+ 	double delta;
+@@ -32,28 +53,33 @@ setmwfact(const char *arg) {
+ 
+ void
+ tile(void) {
+-	unsigned int i, n, nx, ny, nw, nh, mw, th;
++	unsigned int i, n, nx, ny, nw, nh, mw, mh, th;
+ 	Client *c;
+ 
+ 	for(n = 0, c = nexttiled(clients); c; c = nexttiled(c->next))
+ 		n++;
+ 
+ 	/* window geoms */
+-	mw = (n == 1) ? waw : mwfact * waw;
+-	th = (n > 1) ? wah / (n - 1) : 0;
+-	if(n > 1 && th < bh)
++	mh = (n <= nmaster) ? wah / (n > 0 ? n : 1) : wah / nmaster;
++	mw = (n <= nmaster) ? waw : mwfact * waw;
++	th = (n > nmaster) ? wah / (n - nmaster) : 0;
++	if(n > nmaster && th < bh)
+ 		th = wah;
+ 
+ 	nx = wax;
+ 	ny = way;
+ 	for(i = 0, c = nexttiled(clients); c; c = nexttiled(c->next), i++) {
+ 		c->ismax = False;
+-		if(i == 0) { /* master */
++		if(i < nmaster) { /* master */
++			ny = way + i * mh;
+ 			nw = mw - 2 * c->border;
+-			nh = wah - 2 * c->border;
++			nh = mh;
++			if(i + 1 == (n < nmaster ? n : nmaster)) /* remainder */
++				nh = wah - mh * i;
++			nh -= 2 * c->border;
+ 		}
+ 		else {  /* tile window */
+-			if(i == 1) {
++			if(i == nmaster) {
+ 				ny = way;
+ 				nx += mw;
+ 			}
+@@ -64,7 +90,7 @@ tile(void) {
+ 				nh = th - 2 * c->border;
+ 		}
+ 		resize(c, nx, ny, nw, nh, RESIZEHINTS);
+-		if(n > 1 && th != wah)
++		if(n > nmaster && th != wah)
+ 			ny += nh + 2 * c->border;
+ 	}
+ }
